// FloatingLabelInput.tsx
import React, {useState} from 'react';
import {StyleSheet, View, TextInput} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, interpolate, Extrapolation} from 'react-native-reanimated';
export function FloatingLabelInput({label, value, onChange}: {label: string; value: string; onChange: (v: string) => void}) { const [focused, setFocused] = useState(false); const f = useSharedValue(value ? 1 : 0); React.useEffect(() => { f.value = withSpring(focused || value ? 1 : 0, {damping: 22, stiffness: 280}); }, [focused, value]); const labelStyle = useAnimatedStyle(() => ({transform: [{translateY: interpolate(f.value, [0, 1], [16, 0], Extrapolation.CLAMP)}, {scale: interpolate(f.value, [0, 1], [1, 0.75], Extrapolation.CLAMP)}], color: focused ? '#0A84FF' : '#8E8E93'})); return (<View style={s.wrap}><Animated.Text style={[s.label, labelStyle]}>{label}</Animated.Text><TextInput value={value} onChangeText={onChange} onFocus={() => setFocused(true)} onBlur={() => setFocused(false)} style={s.input}/></View>); }
const s = StyleSheet.create({wrap:{paddingTop:14, height:60, backgroundColor:'#1C1C1E', borderRadius:10, paddingHorizontal:14, justifyContent:'flex-end'}, label:{position:'absolute', left:14, fontSize:16, transformOrigin: 'left center' as any}, input:{color:'#fff', fontSize:16, paddingBottom:8}});

