// StampOverlay.tsx
import React from 'react';
import {StyleSheet, Text} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withSequence, withSpring} from 'react-native-reanimated';
export function StampOverlay({visible, label = 'PAID'}: {visible: boolean; label?: string}) { const s = useSharedValue(0); React.useEffect(() => { if (visible) s.value = withSequence(withSpring(1.4, {damping: 8, stiffness: 280}), withSpring(1, {damping: 12, stiffness: 240})); }, [visible]); const style = useAnimatedStyle(() => ({transform: [{scale: s.value}, {rotate: '-15deg'}], opacity: s.value})); return visible ? <Animated.Text style={[ss.stamp, style]}>{label}</Animated.Text> : null; }
const ss = StyleSheet.create({stamp:{position:'absolute', alignSelf:'center', top:'50%', color:'#FF453A', fontSize:48, fontWeight:'900', borderWidth:4, borderColor:'#FF453A', paddingHorizontal:16, paddingVertical:4, letterSpacing:4}});

