import React, {useEffect, useState} from 'react';
import {StyleSheet, View, Text, TextInput} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withTiming} from 'react-native-reanimated';
export function AutoSaveForm({value, onSave}: {value: string; onSave: (v: string) => Promise<void>}) { const [v, setV] = useState(value); const op = useSharedValue(0); useEffect(() => { const t = setTimeout(async () => { await onSave(v); op.value = withTiming(1, {duration: 200}); setTimeout(() => { op.value = withTiming(0, {duration: 500}); }, 1500); }, 800); return () => clearTimeout(t); }, [v]); const style = useAnimatedStyle(() => ({opacity: op.value})); return (<View><TextInput value={v} onChangeText={setV} multiline style={s.input}/><Animated.Text style={[s.saved, style]}>Saved</Animated.Text></View>); }
const s = StyleSheet.create({input:{minHeight:100, padding:14, backgroundColor:'#1C1C1E', borderRadius:10, color:'#fff'}, saved:{position:'absolute', top:8, right:14, color:'#30D158', fontSize:11}});

